// Extract and store summary data + pass video URL forward
const summaryData = $('5. WayinVideo — Get Summary Results').item.json.data;
const videoUrl = $('2. Google Sheets — Read Pending Videos').item.json['Video URL'];
const videoTitle = $('2. Google Sheets — Read Pending Videos').item.json['Video Title'];
const niche = $('2. Google Sheets — Read Pending Videos').item.json['Niche / Category'] || 'General';

// Extract summary fields
const summary = summaryData.summary || '';
const highlights = Array.isArray(summaryData.highlights)
  ? summaryData.highlights.map(h => h.desc).join(' | ')
  : '';
const tags = Array.isArray(summaryData.tags)
  ? summaryData.tags.join(', ')
  : '';

return [{
  json: {
    videoUrl,
    videoTitle,
    niche,
    summary,
    highlights,
    tags
  }
}];

// Extract clips array — split into individual items
const clips = $('11. WayinVideo — Get Clip Results').item.json.data?.clips || [];

if (clips.length === 0) {
  throw new Error('No clips returned from WayinVideo — check if the video URL is valid.');
}

// Get stored data from summary step
const videoUrl = $('8. Code — Store Summary Data').item.json.videoUrl;
const videoTitle = $('8. Code — Store Summary Data').item.json.videoTitle;
const niche = $('8. Code — Store Summary Data').item.json.niche;
const summary = $('8. Code — Store Summary Data').item.json.summary;
const highlights = $('8. Code — Store Summary Data').item.json.highlights;
const tags = $('8. Code — Store Summary Data').item.json.tags;

// Return one item per clip
return clips.map((clip, index) => ({
  json: {
    clipIndex: index + 1,
    clipTitle: clip.title || `Clip ${index + 1}`,
    clipDescription: clip.desc || '',
    clipScore: clip.score || 0,
    clipTags: Array.isArray(clip.tags) ? clip.tags.join(', ') : '',
    exportLink: clip.export_link || '',
    beginMs: clip.begin_ms || 0,
    endMs: clip.end_ms || 0,
    timestampStart: `${Math.floor((clip.begin_ms || 0) / 60000)}:${String(Math.floor(((clip.begin_ms || 0) % 60000) / 1000)).padStart(2, '0')}`,
    timestampEnd: `${Math.floor((clip.end_ms || 0) / 60000)}:${String(Math.floor(((clip.end_ms || 0) % 60000) / 1000)).padStart(2, '0')}`,
    videoUrl,
    videoTitle,
    niche,
    summary,
    highlights,
    tags
  }
}));

// Parse AI caption output into structured fields
const output = $input.first().json.output || '';

// Extract each platform caption
const tiktokMatch = output.match(/TIKTOK_CAPTION:\s*([\s\S]*?)(?=\nFACEBOOK_CAPTION:|$)/);
const facebookMatch = output.match(/FACEBOOK_CAPTION:\s*([\s\S]*?)(?=\nLINKEDIN_CAPTION:|$)/);
const linkedinMatch = output.match(/LINKEDIN_CAPTION:\s*([\s\S]*?)(?=\nHASHTAGS:|$)/);
const hashtagsMatch = output.match(/HASHTAGS:\s*([\s\S]*)$/);

const tiktokCaption = tiktokMatch ? tiktokMatch[1].trim() : '';
const facebookCaption = facebookMatch ? facebookMatch[1].trim() : '';
const linkedinCaption = linkedinMatch ? linkedinMatch[1].trim() : '';
const hashtags = hashtagsMatch ? hashtagsMatch[1].trim() : '';

// Get clip data
const clipData = $('14. Code — Extract Clips Array').item.json;

return [{
  json: {
    tiktokCaption,
    facebookCaption,
    linkedinCaption,
    hashtags,
    clipTitle: clipData.clipTitle,
    clipDescription: clipData.clipDescription,
    clipScore: clipData.clipScore,
    exportLink: clipData.exportLink,
    timestamp: `${clipData.timestampStart} — ${clipData.timestampEnd}`,
    clipIndex: clipData.clipIndex,
    videoUrl: clipData.videoUrl,
    videoTitle: clipData.videoTitle,
    niche: clipData.niche,
    summary: clipData.summary,
    tags: clipData.tags
  }
}];
